def clean_stage4_output(text):
    """Strip %%%PRIORITY_START/END%%% and %%%FCV_RATING:...%%% delimiters; format priority titles."""
    explorer_link = '\n\n*→ For detailed implementation options for this priority, see the Priority Explorer below.*'
    def replace_block(m):
        block = m.group(1).strip()
        lines = block.split('\n')
        title_line = next((l for l in lines if l.startswith('TITLE:')), None)
        if title_line:
            title = title_line.replace('TITLE:', '').strip()
            body_lines = [l for l in lines if not l.startswith('TITLE:')]
            body = '\n'.join(body_lines).strip()
            return f'**▸ {title}**\n\n{body}{explorer_link}'
        return block
    text = re.sub(r'%%%PRIORITY_START%%%(.*?)%%%PRIORITY_END%%%', replace_block, text, flags=re.DOTALL)
    text = re.sub(r'%%%FCV_RATING:[^%]*%%%\n?', '', text)
    return text


def extract_fcv_rating(text):
    """Parse %%%FCV_RATING: [level]%%% from Stage 4 output."""
    m = re.search(r'%%%FCV_RATING:\s*([^%\n]+)%%%', text)
    if m:
        return m.group(1).strip()
    return ''


def extract_priorities(text):
    """Parse %%%PRIORITY_START%%% / %%%PRIORITY_END%%% blocks from Stage 4 output."""
    pattern = r'%%%PRIORITY_START%%%(.*?)%%%PRIORITY_END%%%'
    blocks = re.findall(pattern, text, re.DOTALL)
    priorities = []
    for block in blocks:
        lines = block.strip().split('\n')
        title_line = next((l for l in lines if l.startswith('TITLE:')), None)
        if title_line:
            title = title_line.replace('TITLE:', '').strip()
            body = '\n'.join(l for l in lines if not l.startswith('TITLE:')).strip()
            priorities.append({'title': title, 'body': body})
    # Fallback: positional parsing if fewer than 4 delimiter blocks found
    if len(priorities) < 4:
        fallback = re.findall(r'Priority \d+\s*[·•]\s*[^\n]+', text)
        if fallback and len(fallback) >= len(priorities):
            priorities = [{'title': t.strip(), 'body': ''} for t in fallback]
    return priorities


def load_prompts():
    try:
        if os.path.exists(PROMPTS_FILE):
            with open(PROMPTS_FILE, 'r') as f:
                overrides = json.load(f)
            if overrides:
                merged = dict(DEFAULT_PROMPTS)
                merged.update(overrides)
                return merged
    except Exception:
        pass
    return dict(DEFAULT_PROMPTS)


def save_prompts(prompts_dict):
    with open(PROMPTS_FILE, 'w') as f:
        json.dump(prompts_dict, f, indent=2)


def get_prompt_for_stage(stage):
    return load_prompts().get(str(stage))


def get_stage_name(stage):
    return {1: "Identifying FCV Risks", 2: "FCV-Sensitivity Screening",
            3: "Identifying Project Gaps", 4: "Recommendations Note"}.get(stage, f"Stage {stage}")


# ── PDF helper ───────────────────────────────────────────────────────────────

def extract_pdf_text(b64_data, name):
    try:
        pdf_bytes = base64.standard_b64decode(b64_data)
        reader = PdfReader(io.BytesIO(pdf_bytes))
        pages_text = []
        for page in reader.pages:
            try:
                pages_text.append(page.extract_text() or '')
            except Exception:
                pages_text.append('')
        full_text = '\n\n'.join(pages_text)
        page_count = len(reader.pages)
        if len(full_text) > MAX_DOC_CHARS:
            full_text = full_text[:MAX_DOC_CHARS] + (
                f'\n\n[Document truncated at {MAX_DOC_CHARS//1000}k chars of {page_count} pages.]'
            )
        return full_text, page_count
    except Exception as e:
        return f'[Could not extract text from {name}: {str(e)}]', 0


